 98→pub struct AnthropicClient {
 99→    client: Client,
100→    api_url: String,
101→    api_key: Option<String>,
102→}
103→
104→impl AnthropicClient {
105→    pub fn new(api_url: &str) -> Self {
106→        let client = Client::builder()
107→            .connect_timeout(Duration::from_secs(30))
108→            .timeout(Duration::from_secs(300))
109→            .build()
110→            .expect("failed to build HTTP client");
111→
112→        let api_key = std::env::var("ANTHROPIC_API_KEY").ok();
113→
114→        Self {
115→            client,
116→            api_url: api_url.trim_end_matches('/').to_string(),
117→            api_key,
118→        }
119→    }
120→
121→    pub fn api_url(&self) -> &str {
122→        &self.api_url
123→    }
124→
125→    pub fn has_api_key(&self) -> bool {
126→        self.api_key.is_some()
127→    }
128→
129→    pub async fn send_message(
130→        &self,
131→        model: &str,
132→        max_tokens: u32,
133→        system: &str,
134→        messages: &[Message],
135→        tools: &[serde_json::Value],
136→        stream_callback: &mut dyn FnMut(&str),
137→    ) -> Result<(Vec<ContentBlock>, StopReason, Usage), AgentError> {
138→        let url = format!("{}/v1/messages", self.api_url);
139→
140→        let mut body = serde_json::json!({
141→            "model": model,
142→            "max_tokens": max_tokens,
143→            "system": system,
144→            "messages": messages,
145→            "stream": true,
146→        });
147→
148→        if !tools.is_empty() {
149→            body["tools"] = serde_json::Value::Array(tools.to_vec());
150→        }
151→
152→        let mut req = self
153→            .client
154→            .post(&url)
155→            .header("content-type", "application/json")
156→            .header("anthropic-version", "2023-06-01");
157→
158→        if let Some(ref key) = self.api_key {
159→            req = req.header("x-api-key", key);
160→        }
161→
162→        let resp: reqwest::Response = req.json(&body).send().await?;
163→
164→        let status = resp.status();
165→        if !status.is_success() {
166→            let retry_after: Option<u64> = resp
167→                .headers()
168→                .get("retry-after")
169→                .and_then(|v| v.to_str().ok())
170→                .and_then(|s| s.parse::<u64>().ok());
171→            let body_text = resp.text().await.unwrap_or_default();
172→            return Err(AgentError::HttpError {
173→                status: status.as_u16(),
174→                retry_after,
175→                body: body_text,
176→            });
177→        }
178→
179→        let stream = resp.bytes_stream();
180→        parse_sse_stream(stream, stream_callback).await
181→    }
182→}
183→
184→/// Parse SSE stream into content blocks, stop reason, and usage.
185→///
186→/// We collect content_block_start events to initialize blocks, then
187→/// content_block_delta events to append text or accumulate tool input JSON,
188→/// message_start for input usage, and message_delta for stop_reason + output usage.
189→async fn parse_sse_stream<S>(
190→    stream: S,
191→    callback: &mut dyn FnMut(&str),
192→) -> Result<(Vec<ContentBlock>, StopReason, Usage), AgentError>
193→where
194→    S: futures_util::Stream<Item = Result<bytes::Bytes, reqwest::Error>> + Unpin,
195→{
196→    let mut content_blocks: Vec<ContentBlock> = Vec::new();
197→    let mut stop_reason: Option<StopReason> = None;
198→    let mut usage = Usage::default();
199→    let mut buffer = String::new();
200→
201→    // Track in-progress tool_use input JSON accumulation per block index
202→    let mut tool_input_bufs: std::collections::HashMap<usize, String> =
203→        std::collections::HashMap::new();
204→
205→    futures_util::pin_mut!(stream);
206→
207→    while let Some(chunk_result) = stream.next().await {
208→        let chunk = chunk_result.map_err(|e| AgentError::StreamTransient(e.to_string()))?;
209→        buffer.push_str(&String::from_utf8_lossy(&chunk));
210→
211→        // Process complete SSE lines
212→        while let Some(pos) = buffer.find("\n\n") {
213→            {
214→                let event_block = &buffer[..pos];
215→
216→                for line in event_block.lines() {
217→                    if let Some(data) = line.strip_prefix("data: ") {
218→                        if data == "[DONE]" {
219→                            continue;
220→                        }
221→
222→                        let parsed: serde_json::Value = match serde_json::from_str(data) {
223→                            Ok(v) => v,
224→                            Err(_) => continue,
225→                        };
226→
227→                        let event_type = parsed["type"].as_str().unwrap_or("");
228→
229→                        match event_type {
230→                            "message_start" => {
231→                                if let Some(u) = parsed.get("message").and_then(|m| m.get("usage"))
232→                                {
233→                                    usage.input_tokens = u["input_tokens"].as_u64().unwrap_or(0);
234→                                    usage.cache_creation_input_tokens =
235→                                        u["cache_creation_input_tokens"].as_u64().unwrap_or(0);
236→                                    usage.cache_read_input_tokens =
237→                                        u["cache_read_input_tokens"].as_u64().unwrap_or(0);
238→                                }
239→                            }
240→                            "content_block_start" => {
241→                                let cb = &parsed["content_block"];
242→                                match cb["type"].as_str() {
243→                                    Some("text") => {
244→                                        content_blocks.push(ContentBlock::Text {
245→                                            text: String::new(),
246→                                        });
247→                                    }
248→                                    Some("tool_use") => {
249→                                        let idx = content_blocks.len();
250→                                        content_blocks.push(ContentBlock::ToolUse {
251→                                        id: cb["id"].as_str().unwrap_or("").to_string(),
252→                                        name: cb["name"].as_str().unwrap_or("").to_string(),
253→                                        input: serde_json::Value::Object(serde_json::Map::new()),
254→                                    });
255→                                        tool_input_bufs.insert(idx, String::new());
256→                                    }
257→                                    _ => {}
258→                                }
259→                            }
260→                            "content_block_delta" => {
261→                                let index = parsed["index"].as_u64().unwrap_or(0) as usize;
262→                                let delta = &parsed["delta"];
263→
264→                                match delta["type"].as_str() {
265→                                    Some("text_delta") => {
266→                                        if let Some(text) = delta["text"].as_str() {
267→                                            callback(text);
268→                                            if let Some(ContentBlock::Text { text: ref mut t }) =
269→                                                content_blocks.get_mut(index)
270→                                            {
271→                                                t.push_str(text);
272→                                            }
273→                                        }
274→                                    }
275→                                    Some("input_json_delta") => {
276→                                        if let Some(partial) = delta["partial_json"].as_str() {
277→                                            if let Some(buf) = tool_input_bufs.get_mut(&index) {
278→                                                buf.push_str(partial);
279→                                            }
280→                                        }
281→                                    }
282→                                    _ => {}
283→                                }
284→                            }
285→                            "content_block_stop" => {
286→                                let index = parsed["index"].as_u64().unwrap_or(0) as usize;
287→                                // Finalize tool_use input JSON
288→                                if let Some(json_str) = tool_input_bufs.remove(&index) {
289→                                    if let Some(ContentBlock::ToolUse { ref mut input, .. }) =
290→                                        content_blocks.get_mut(index)
291→                                    {
292→                                        if let Ok(v) =
293→                                            serde_json::from_str::<serde_json::Value>(&json_str)
294→                                        {
295→                                            *input = v;
296→                                        }
297→                                    }
298→                                }
299→                            }
300→                            "message_delta" => {
301→                                if let Some(sr) = parsed["delta"]["stop_reason"].as_str() {
302→                                    stop_reason = match sr {
303→                                        "end_turn" => Some(StopReason::EndTurn),
304→                                        "max_tokens" => Some(StopReason::MaxTokens),
305→                                        "tool_use" => Some(StopReason::ToolUse),
306→                                        _ => None,
307→                                    };
308→                                }
309→                                if let Some(u) = parsed.get("usage") {
310→                                    usage.output_tokens = u["output_tokens"].as_u64().unwrap_or(0);
311→                                }
312→                            }
313→                            "error" => {
314→                                let err_type =
315→                                    parsed["error"]["type"].as_str().unwrap_or("unknown");
316→                                let err_msg = parsed["error"]["message"]
317→                                    .as_str()
318→                                    .unwrap_or("unknown error");
319→                                match err_type {
320→                                    "overloaded_error" | "api_error" | "rate_limit_error" => {
321→                                        return Err(AgentError::StreamTransient(format!(
322→                                            "{err_type}: {err_msg}"
323→                                        )));
324→                                    }
325→                                    _ => {
326→                                        return Err(AgentError::StreamParse(format!(
327→                                            "{err_type}: {err_msg}"
328→                                        )));
329→                                    }
330→                                }
331→                            }
332→                            _ => {}
333→                        }
334→                    }
335→                }
336→            }
337→            buffer.drain(..pos + 2);
338→        }
339→    }
340→
341→    let stop = stop_reason.ok_or_else(|| {
342→        AgentError::StreamTransient(
343→            "stream ended without stop_reason (connection drop)".to_string(),
344→        )
345→    })?;
346→
347→    Ok((content_blocks, stop, usage))
348→}
