 797→const MAX_CONTINUATIONS: usize = 3;
 798→
 799→/// Determine what to do after a MaxTokens stop_reason.
 800→/// Returns the action to take given the filtered content blocks and current continuation count.
 801→#[derive(Debug, PartialEq)]
 802→enum MaxTokensAction {
 803→    /// Response was empty (only placeholder) — break immediately
 804→    BreakEmpty,
 805→    /// Valid tool_use blocks present — fall through to tool dispatch
 806→    DispatchTools,
 807→    /// Text-only, under cap — inject continuation prompt
 808→    Continue,
 809→    /// Text-only, cap reached — break
 810→    BreakCapReached,
 811→}
 812→
 813→fn classify_max_tokens(blocks: &[ContentBlock], continuation_count: usize) -> MaxTokensAction {
 814→    // Check for empty response (only the "[Response truncated]" placeholder)
 815→    let is_empty = blocks.len() == 1
 816→        && matches!(&blocks[0], ContentBlock::Text { text } if text == "[Response truncated]");
 817→    if is_empty {
 818→        return MaxTokensAction::BreakEmpty;
 819→    }
 820→
 821→    let has_valid_tools = blocks
 822→        .iter()
 823→        .any(|b| matches!(b, ContentBlock::ToolUse { .. }));
 824→
 825→    if has_valid_tools {
 826→        MaxTokensAction::DispatchTools
 827→    } else if continuation_count < MAX_CONTINUATIONS {
 828→        MaxTokensAction::Continue
 829→    } else {
 830→        MaxTokensAction::BreakCapReached
 831→    }
 832→}
